#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100005
#define INF 0x3f3f3f3f

int n, m;
int edge[MAX][MAX][2];
int dp[MAX][33];

void bfs(int start) {
    int queue[MAX], front = 0, rear = 0;
    queue[rear++] = start;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 1; v <= n; v++) {
            if (edge[u][v][0] != -1) {
                int l = edge[u][v][0], r = edge[u][v][1];
                for (int i = l; i <= r; i++) {
                    if (dp[u][i] != -1) {
                        dp[v][i] = dp[u][i] + 1;
                        queue[rear++] = v;
                    }
                }
            }
        }
    }
}

int main() {
    scanf("%d %d", &n, &m);
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            edge[i][j][0] = edge[i][j][1] = -1;
        }
    }
    for (int i = 1; i <= m; i++) {
        int u, v, l, r;
        scanf("%d %d %d %d", &u, &v, &l, &r);
        edge[u][v][0] = l;
        edge[u][v][1] = r;
    }
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= 32; j++) {
            dp[i][j] = -1;
        }
    }
    for (int i = 1; i <= 32; i++) {
        dp[1][i] = 0;
    }
    bfs(1);
    int ans = 0;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= 32; j++) {
            if (dp[i][j] != -1) {
                ans += dp[i][j];
            }
        }
    }
    printf("%d\n", ans);
    return 0;
}

