import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    static final int MAX = 100005;
    static final int INF = 0x3f3f3f3f;
    static int n, m;
    static int[][] edge = new int[MAX][MAX];
    static int[][] dp = new int[MAX][33];
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        n = sc.nextInt();
        m = sc.nextInt();
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                edge[i][j] = -1;
            }
        }
        for (int i = 1; i <= m; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            int l = sc.nextInt();
            int r = sc.nextInt();
            edge[u][v] = l;
            edge[u][v + n] = r;
        }
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= 32; j++) {
                dp[i][j] = -1;
            }
        }
        for (int i = 1; i <= 32; i++) {
            dp[1][i] = 0;
        }
        bfs(1);
        int ans = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= 32; j++) {
                if (dp[i][j] != -1) {
                    ans += dp[i][j];
                }
            }
        }
        System.out.println(ans);
    }
    public static void bfs(int start) {
        Queue<Integer> q = new LinkedList<>();
        q.add(start);
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v = 1; v <= n; v++) {
                if (edge[u][v] != -1) {
                    int l = edge[u][v];
                    int r = edge[u][v + n];
                    for (int i = l; i <= r; i++) {
                        if (dp[u][i] != -1) {
                            dp[v][i] = dp[u][i] + 1;
                            q.add(v);
                        }
                    }
                }
            }
        }
    }
}

